import{_ as s,o as t,c as a,ag as l}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"vertical-slice-issues","description":"","frontmatter":{"title":"vertical-slice-issues","concept":"垂直切片 Issue","concept_id":"vertical-slice-issues","aliases":[],"sources":["02_Library/ADK_Agent_Skills/[ADK_Agent_Skills] My AI-Assisted workflow.md"],"related_concepts":["[[ai-assisted-workflow]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/vertical-slice-issues.md","filePath":"wiki/concepts/vertical-slice-issues.md","lastUpdated":null}'),i={name:"wiki/concepts/vertical-slice-issues.md"};function r(o,e,c,n,d,h){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="垂直切片-issue-vertical-slice-issues" tabindex="-1">垂直切片 Issue (Vertical Slice Issues) <a class="header-anchor" href="#垂直切片-issue-vertical-slice-issues" aria-label="Permalink to &quot;垂直切片 Issue (Vertical Slice Issues)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在 AI 驱动的项目开发中，任务拆解必须遵循“贯穿所有层级（从前端到数据库）”的原子化路径设计，以保证 AI 每个子任务的输出均可验证闭环。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>拒绝横向分层拆解</strong>：针对单一技术栈层面（只动数据库，或只动 UI）的工单不利于 AI 完成闭环校验（来源：<a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - My AI-Assisted workflow.html">[ADK_Agent_Skills] My AI-Assisted workflow.md</a>）</li><li><strong>Tracer Bullets 验证</strong>：切片需要是一颗“曳光弹”，完成后的状态必须是功能层面端到端可验证或演示的。</li><li><strong>AFK 与 HITL 分类</strong>：每个垂直切片明确是否需要人类离开键盘 (Away From Keyboard) 或保持在线干预 (Human In The Loop)。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>给 AI 下达复杂迭代指令时，必须按用户故事贯穿各个模块：如“用户登录页面的邮箱校验和接口验证”作为一个任务，而不是把“写前端”和“写后端”拆为两个平行的 Agent Task。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/ai-assisted-workflow.html">ai-assisted-workflow</a> — AI 高效执行的前提依赖于正确的任务下发格式。</li></ul><h2 id="源文章引用" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/ADK_Agent_Skills/ADK_Agent_Skills - My AI-Assisted workflow.html">[ADK_Agent_Skills] My AI-Assisted workflow.md</a></td><td>&quot;tracer bullets that cut through every integration layer end-to-end rather than horizontal slices of a single layer. A slice that only touches the database, or only touches the UI, is not a valid slice.&quot;</td></tr></tbody></table>',11)])])}const A=s(i,[["render",r]]);export{_ as __pageData,A as default};
